import argparse
from kafka.admin import KafkaAdminClient, NewTopic, ConfigResource, ConfigResourceType

def create_topic(admin_client, topic_name, num_partitions, replication_factor, configs):
    topic = NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor, topic_configs=configs)
    admin_client.create_topics([topic])

def alter_configs(admin_client, topic_name, configs):
    resource = ConfigResource(ConfigResourceType.TOPIC, topic_name, configs=configs)
    admin_client.alter_configs([resource])

def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration')
    parser.add_argument('--bootstrap-server', required=True, help='Kafka bootstrap server')
    parser.add_argument('--create-topic', help='Name of the topic to be created')
    parser.add_argument('--num-partitions', type=int, help='Number of partitions for the topic')
    parser.add_argument('--replication-factor', type=int, help='Replication factor for the topic')
    parser.add_argument('--config', action='append', help='Configuration for the topic as key=value')
    parser.add_argument('--alter-config', help='Alter config of an existing topic')
    args = parser.parse_args()

    admin_client = KafkaAdminClient(bootstrap_servers=args.bootstrap_server)

    configs = dict()
    if args.config:
        for conf in args.config:
            key, value = conf.split('=')
            configs[key] = value

    if args.create_topic:
        create_topic(admin_client, args.create_topic, args.num_partitions, args.replication_factor, configs)

    if args.alter_config:
        alter_configs(admin_client, args.alter_config, configs)

    admin_client.close()

if __name__ == '__main__':
    main()